content:
{
  "sentences": [
    {
      "text": "今天天氣太熱了，我有點不舒服。",
      "pinyin": "Jīntiān tiānqì tài rè le, wǒ yǒudiǎn bù shūfu.",
      "pinyin_numeric": "jin1tian1 tian1qi4 tai4 re4 le0, wo3 you3dian3 bu4 shu1fu0.",
      "translation_en": "The weather is too hot today; I feel a bit uncomfortable.",
      "translation_ko": "오늘 날씨가 너무 더워서 좀 불편해요."
    },
    {
      "text": "昨天颱風太大，我心情很緊張。",
      "pinyin": "Zuótiān táifēng tài dà le, wǒ xīnqíng hěn jǐnzhāng.",
      "pinyin_numeric": "zuo2tian1 tai2feng1 tai4 da4 le0, wo3 xin1qing2 hen3 jin3zhang1.",
      "translation_en": "The typhoon was too strong yesterday; I was very nervous.",
      "translation_ko": "어제 태풍이 너무 커서 마음이 긴장됐어요."
    },
    {
      "text": "這家咖啡店太安靜了，我喜歡熱鬧的地方。",
      "pinyin": "Zhè jiā kāfēi diàn tài ānjìng le, wǒ xǐhuān rènào de dìfang.",
      "pinyin_numeric": "zhe4 jia1 ka1fei1 dian4 tai4 an1jing4 le0, wo3 xi3huan1 re4nao4 de0 di4fang0.",
      "translation_en": "This coffee shop is too quiet; I like lively places.",
      "translation_ko": "이 카페는 너무 조용해서 저는 시끌벅적한 곳을 좋아해요."
    },
    {
      "text": "今天下午天氣太悶熱了，我想喝冰水。",
      "pinyin": "Jīntiān xiàwǔ tiānqì tài mēnrè le, wǒ xiǎng hē bīng shuǐ.",
      "pinyin_numeric": "jin1tian1 xia4wu3 tian1qi4 tai4 men1re4 le0, wo3 xiang3 he1 bing1 shui3.",
      "translation_en": "The weather is too muggy this afternoon; I want to drink ice water.",
      "translation_ko": "오늘 오후 날씨가 너무 후덥지근해서 얼음물을 마시고 싶어요."
    },
    {
      "text": "明天是晴天，我的心情太好了。",
      "pinyin": "Míngtiān shì qíngtiān, wǒ de xīnqíng tài hǎo le.",
      "pinyin_numeric": "ming2tian1 shi4 qing2tian1, wo3 de0 xin1qing2 tai4 hao3 le0.",
      "translation_en": "Tomorrow will be sunny; my mood is too good.",
      "translation_ko": "내일은 맑은 날씨라서 제 기분이 너무 좋아요."
    },
    {
      "text": "這條路太滑了，走路要小心。",
      "pinyin": "Zhè tiáo lù tài huá le, zǒulù yào xiǎoxīn.",
      "pinyin_numeric": "zhe4 tiao2 lu4 tai4 hua2 le0, zou3lu4 yao4 xiao3xin1.",
      "translation_en": "This road is too slippery; you need to walk carefully.",
      "translation_ko": "이 길이 너무 미끄러워서 걸을 때 조심해야 해요."
    },
    {
      "text": "今天溫度三十度，太熱了，我不想出門。",
      "pinyin": "Jīntiān wēndù sānshí dù, tài rè le, wǒ bù xiǎng chūmén.",
      "pinyin_numeric": "jin1tian1 wen1du4 san1shi2 du4, tai4 re4 le0, wo3 bu4 xiang3 chu1men2.",
      "translation_en": "Today's temperature is 30 degrees; it's too hot, I don't want to go out.",
      "translation_ko": "오늘 기온이 30도라서 너무 더워서 밖에 나가고 싶지 않아요."
    },
    {
      "text": "下雨天我的心情太差了，因為不能去公園。",
      "pinyin": "Xiàyǔ tiān wǒ de xīnqíng tài chà le, yīnwèi bù néng qù gōngyuán.",
      "pinyin_numeric": "xia4yu3 tian1 wo3 de0 xin1qing2 tai4 cha4 le0, yin1wei4 bu4 neng2 qu4 gong1yuan2.",
      "translation_en": "My mood is too bad on rainy days because I can't go to the park.",
      "translation_ko": "비 오는 날은 기분이 너무 안 좋아요. 공원에 갈 수 없으니까요."
    },
    {
      "text": "這件外套太厚了，今天天氣很熱。",
      "pinyin": "Zhè jiàn wàitào tài hòu le, jīntiān tiānqì hěn rè.",
      "pinyin_numeric": "zhe4 jian4 wai4tao4 tai4 hou4 le0, jin1tian1 tian1qi4 hen3 re4.",
      "translation_en": "This jacket is too thick; the weather is hot today.",
      "translation_ko": "이 외투가 너무 두꺼워요. 오늘 날씨가 더운데요."
    },
    {
      "text": "今天天氣太冷了，我穿外套，可是還是有點不舒服。",
      "pinyin": "Jīntiān tiānqì tài lěng le, wǒ chuān wàitào, kěshì háishì yǒudiǎn bù shūfu.",
      "pinyin_numeric": "jin1tian1 tian1qi4 tai4 leng3 le0, wo3 chuan1 wai4tao4, ke3shi4 hai2shi4 you3dian3 bu4 shu1fu0.",
      "translation_en": "The weather is too cold today; I wore a jacket, but I still feel a bit uncomfortable.",
      "translation_ko": "오늘 날씨가 너무 추워서 외투를 입었는데도 여전히 좀 불편해요."
    }
  ]
}
